import { By } from "selenium-webdriver";
import ojwd, { DriverLike, register } from "../../";
import { OjNBox } from "./OjNBox";
export { OjNBox };

/**
 * Create an instance of [[OjNBox]].  This function will first wait for
 * the element to appear in the DOM before trying to locate it.
 * @example
 * <code>
 * const el = await ojNBox(driver, By.id('my-oj-n-box'))
 * </code>
 * @param driver A WebDriver/WebElement instance used to locate the component
 * element.
 * @param by The By locator with which to find the element
 */
export async function ojNBox(driver: DriverLike, by: By): Promise<OjNBox> {
  const webEl = await driver.findElement(by);
  // Check that the element is of type OjNBox
  if (!(webEl instanceof OjNBox)) {
    const tagName = await webEl.getTagName();
    throw Error(`Locator '${by}' located a <${tagName}>, but expected <oj-n-box>`);
  }
  return webEl;
}

register("oj-n-box", OjNBox);
